async (params, browser) => {
  // Open Strava
  await browser.open('https://www.strava.com/dashboard')

  // Wait for page
  await browser.waitForSelector('.feed, .activity-feed, [class*="Feed"]', 15000)

  // Let page render
  await browser.wait(2500)

  // Extract data
  const result = await browser.evaluate(`const activities = []; document.querySelectorAll('.activity, [class*="FeedEntry"], .feed-entry').forEach((el, i) => { if (i < 10) { const nameEl = el.querySelector('.entry-owner, a[href*="/athletes/"]'); const titleEl = el.querySelector('.entry-title, h3, a[href*="/activities/"]'); const statsEl = el.querySelector('.entry-stats, .stat'); activities.push({ athlete: nameEl?.textContent?.trim() || '', title: titleEl?.textContent?.trim() || '', stats: statsEl?.textContent?.trim() || '' }); } }); return { activity_count: activities.length, activities };`)

  return result
}
